// Auto-migrated from the original static guide HTML. Structural markup
// and code samples are preserved; inline styles, scripts, and the guide's
// own bespoke syntax-highlight token classes were stripped so every guide
// renders through the one shared GuideReader stylesheet.
export const html: string = "<section id=\"g1\">\n<h3><span>1.1</span>What is Gunicorn?</h3>\n<div class=\"callout\"><strong>In one sentence</strong>Gunicorn is a process manager that runs multiple copies of your Django app at once and routes incoming requests to whichever copy is free.</div>\n<p><strong>Gunicorn</strong> (short for \"Green Unicorn\") is a <strong>WSGI HTTP server</strong> for Python web applications. When you run <code>python manage.py runserver</code>, Django spins up one process that can only ever do one thing at a time -- handle request A fully, <em>then</em> handle request B. That's fine for development. It is not fine for production, where dozens of users might hit your site in the same second.</p>\n<p>Gunicorn solves this by starting your Django application multiple times as separate OS processes -- called <strong>workers</strong> -- and acting as the traffic cop in front of them. A request comes in, Gunicorn hands it to whichever worker is idle, that worker processes it and sends back a response, and Gunicorn moves on to the next request. Your Django code doesn't change at all; Gunicorn just runs more copies of it.</p>\n<div>Gunicorn does <strong>not</strong> talk directly to the internet in a typical production setup. It listens on a local port or Unix socket, and Nginx (Chapter 2) sits in front of it facing the public internet. This split is deliberate -- each tool does the one job it's actually good at.</div>\n</section>\n<section id=\"g2\">\n<h3><span>1.2</span>The process model: master and workers</h3>\n<div class=\"callout\"><strong>Why this matters</strong>Understanding that Gunicorn is a master process managing child workers explains almost every configuration option and every weird production bug you'll ever debug with it.</div>\n<p>Gunicorn always runs as one <strong>master process</strong> plus a configurable number of <strong>worker processes</strong>. The master never handles a single HTTP request itself -- its only job is bookkeeping: starting workers, restarting any that crash, and shutting everything down cleanly on exit.</p>\n<div class=\"diagram\">\n<svg viewbox=\"0 0 760 280\" xmlns=\"http://www.w3.org/2000/svg\">\n<defs>\n<marker id=\"arrowAmber\" markerheight=\"8\" markerwidth=\"8\" orient=\"auto\" refx=\"6\" refy=\"4\"><path d=\"M0,0 L8,4 L0,8 Z\" fill=\"#ffb020\"></path></marker>\n</defs>\n<!-- master -->\n<rect fill=\"#171a22\" height=\"56\" rx=\"8\" stroke=\"#ffb020\" stroke-width=\"1.5\" width=\"160\" x=\"300\" y=\"20\"></rect>\n<text fill=\"#e9ebf1\" font-family=\"IBM Plex Mono, monospace\" font-size=\"13\" font-weight=\"600\" text-anchor=\"middle\" x=\"380\" y=\"44\">Master Process</text>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"10.5\" text-anchor=\"middle\" x=\"380\" y=\"62\">PID 1001 \u00b7 manages workers</text>\n<!-- arrows down to workers -->\n<line marker-end=\"url(#arrowAmber)\" stroke=\"#ffb020\" stroke-width=\"1.5\" x1=\"340\" x2=\"160\" y1=\"76\" y2=\"130\"></line>\n<line marker-end=\"url(#arrowAmber)\" stroke=\"#ffb020\" stroke-width=\"1.5\" x1=\"380\" x2=\"380\" y1=\"76\" y2=\"130\"></line>\n<line marker-end=\"url(#arrowAmber)\" stroke=\"#ffb020\" stroke-width=\"1.5\" x1=\"420\" x2=\"600\" y1=\"76\" y2=\"130\"></line>\n<!-- worker boxes -->\n<g>\n<rect fill=\"#0a0c10\" height=\"64\" rx=\"8\" stroke=\"#3a3f4e\" stroke-width=\"1.5\" width=\"160\" x=\"80\" y=\"130\"></rect>\n<text fill=\"#e9ebf1\" font-family=\"IBM Plex Mono, monospace\" font-size=\"12.5\" font-weight=\"600\" text-anchor=\"middle\" x=\"160\" y=\"155\">Worker 1</text>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"10\" text-anchor=\"middle\" x=\"160\" y=\"172\">PID 1002 \u00b7 full Django app</text>\n</g>\n<g>\n<rect fill=\"#0a0c10\" height=\"64\" rx=\"8\" stroke=\"#3a3f4e\" stroke-width=\"1.5\" width=\"160\" x=\"300\" y=\"130\"></rect>\n<text fill=\"#e9ebf1\" font-family=\"IBM Plex Mono, monospace\" font-size=\"12.5\" font-weight=\"600\" text-anchor=\"middle\" x=\"380\" y=\"155\">Worker 2</text>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"10\" text-anchor=\"middle\" x=\"380\" y=\"172\">PID 1003 \u00b7 full Django app</text>\n</g>\n<g>\n<rect fill=\"#0a0c10\" height=\"64\" rx=\"8\" stroke=\"#3a3f4e\" stroke-width=\"1.5\" width=\"160\" x=\"520\" y=\"130\"></rect>\n<text fill=\"#e9ebf1\" font-family=\"IBM Plex Mono, monospace\" font-size=\"12.5\" font-weight=\"600\" text-anchor=\"middle\" x=\"600\" y=\"155\">Worker 3</text>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"10\" text-anchor=\"middle\" x=\"600\" y=\"172\">PID 1004 \u00b7 full Django app</text>\n</g>\n<!-- requests coming in -->\n<line stroke=\"#3a3f4e\" stroke-dasharray=\"3,3\" stroke-width=\"1.5\" x1=\"160\" x2=\"160\" y1=\"194\" y2=\"240\"></line>\n<line stroke=\"#3a3f4e\" stroke-dasharray=\"3,3\" stroke-width=\"1.5\" x1=\"380\" x2=\"380\" y1=\"194\" y2=\"240\"></line>\n<line stroke=\"#3a3f4e\" stroke-dasharray=\"3,3\" stroke-width=\"1.5\" x1=\"600\" x2=\"600\" y1=\"194\" y2=\"240\"></line>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"10.5\" text-anchor=\"middle\" x=\"160\" y=\"256\">handles request A</text>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"10.5\" text-anchor=\"middle\" x=\"380\" y=\"256\">idle, ready</text>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"10.5\" text-anchor=\"middle\" x=\"600\" y=\"256\">handles request B</text>\n</svg>\n</div>\n<p class=\"diagram-caption\">The master spawns and supervises N independent worker processes -- each one a complete, isolated copy of your Django app.</p>\n<p>Because each worker is a separate OS process with its <strong>own memory space</strong>, a crash, memory leak, or even an unhandled exception in one worker cannot take down the others. The master simply notices the dead worker and starts a replacement. This isolation is the entire reason Gunicorn is reliable enough for production.</p>\n</section>\n<section id=\"g3\">\n<h3><span>1.3</span>Worker types: sync, threads, and async</h3>\n<div class=\"callout\"><strong>Why this matters</strong>Gunicorn supports several worker classes, and picking the wrong one is the single most common cause of a Django site that \"works fine in testing\" but falls over under real load.</div>\n<p>A <strong>worker class</strong> determines how a single worker process handles concurrency internally:</p>\n<div class=\"tbl-wrap\">\n<table class=\"gtbl\">\n<tr><th>Worker class</th><th>Concurrency model</th><th>Best for</th></tr>\n<tr><td><code>sync</code> (default)</td><td>One request at a time per worker, full stop</td><td>CPU-bound work, the simplest mental model, most Django sites</td></tr>\n<tr><td><code>gthread</code></td><td>Multiple threads per worker share I/O waits</td><td>Sites with many slow I/O calls (external APIs) but no heavy GIL contention</td></tr>\n<tr><td><code>gevent</code> / <code>eventlet</code></td><td>Greenlets cooperatively multitask within one process</td><td>Very high concurrency, mostly I/O-bound (chat, polling, webhooks)</td></tr>\n<tr><td><code>uvicorn.workers.UvicornWorker</code></td><td>True async event loop (ASGI, not WSGI)</td><td>WebSockets, async views, Django Channels -- see Chapter 3</td></tr>\n</table>\n</div>\n<p>For a typical Django site with no WebSockets, <code>sync</code> workers are the right default -- they are the easiest to reason about and the hardest to misconfigure. You scale capacity by running <em>more sync workers</em>, not by making one worker juggle more requests internally.</p>\n</section>\n<section id=\"g4\">\n<h3><span>1.4</span>Installing and running Gunicorn</h3>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-lang\">Terminal</span></div>\n<pre>pip install gunicorn\npip freeze &gt; requirements.txt\n\n<span># Run it pointed at your WSGI application object</span>\ngunicorn myproject.wsgi:application --bind 0.0.0.0:8000 --workers 3</pre>\n</div>\n<p><code>myproject.wsgi:application</code> tells Gunicorn exactly where to find the callable it should run: the module path <code>myproject.wsgi</code>, and inside it, the variable named <code>application</code>. This is the same <code>wsgi.py</code> file Django generates automatically in every new project.</p>\n<div class=\"tone-tip\"><strong>Tip:</strong> While testing, add <code>--reload</code> so Gunicorn restarts workers automatically when your code changes -- never use this flag in production, since it adds filesystem-watching overhead with zero benefit once your code stops changing live.</div>\n</section>\n<section id=\"g5\">\n<h3><span>1.5</span>The config file: gunicorn.conf.py</h3>\n<div class=\"callout\"><strong>Why this matters</strong>Long command-line flags get unwieldy and easy to typo across environments. A config file is versioned, reviewable, and consistent between staging and production.</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-lang\">Python</span><span class=\"code-file\">gunicorn.conf.py</span></div>\n<pre><span># Socket / binding</span>\nbind = <span>\"unix:/run/gunicorn.sock\"</span> <span># or \"0.0.0.0:8000\"</span>\n\n<span># Process model</span>\nworkers = <span>4</span> <span># see 1.6 for the formula</span>\nworker_class = <span>\"sync\"</span>\nthreads = <span>1</span>\n\n<span># Timeouts</span>\ntimeout = <span>30</span> <span># kill + restart a worker stuck past 30s</span>\ngraceful_timeout = <span>30</span>\nkeepalive = <span>5</span>\n\n<span># Logging</span>\naccesslog = <span>\"-\"</span> <span># \"-\" means stdout</span>\nerrorlog = <span>\"-\"</span>\nloglevel = <span>\"info\"</span>\n\n<span># Reliability</span>\nmax_requests = <span>1000</span> <span># restart a worker after N requests</span>\nmax_requests_jitter = <span>50</span> <span># add randomness so workers don't all restart together</span>\npreload_app = <span>True</span> <span># load app once in master, fork workers from it</span></pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-lang\">Terminal</span></div>\n<pre>gunicorn myproject.wsgi:application -c gunicorn.conf.py</pre>\n</div>\n<div><code>max_requests</code> is a defense against slow memory leaks. Even a small leak per request adds up over millions of requests -- periodically retiring and replacing workers keeps memory usage flat over weeks of uptime instead of climbing until the server runs out of RAM.</div>\n</section>\n<section id=\"g6\">\n<h3><span>1.6</span>Tuning worker count and timeouts</h3>\n<div class=\"callout\"><strong>Why this matters</strong>Too few workers and requests queue up under load; too many and you exhaust RAM or database connections. There's a well-tested formula to start from.</div>\n<p>Gunicorn's own documentation recommends a simple starting formula for <code>sync</code> workers:</p>\n<div class=\"stat-grid\">\n<div class=\"stat-card\"><div>(2 \u00d7 cores) + 1</div><div>Worker count formula</div></div>\n<div class=\"stat-card\"><div>~30s</div><div>Typical request timeout</div></div>\n<div class=\"stat-card\"><div>~30\u201350MB</div><div>RAM per Django worker</div></div>\n</div>\n<p>So a 2-core server starts at <strong>5 workers</strong>; a 4-core server starts at <strong>9 workers</strong>. This isn't a hard law -- it's a reasonable starting point for a typical mixed CPU/IO Django workload, which you then adjust based on real memory and CPU graphs in production.</p>\n<table class=\"gtbl\">\n<tr><th>Symptom</th><th>Likely cause</th><th>Fix</th></tr>\n<tr><td>Requests queue, server has CPU to spare</td><td>Too few workers</td><td>Increase <code>workers</code></td></tr>\n<tr><td>Server runs out of memory</td><td>Too many workers, or a leak</td><td>Reduce <code>workers</code>, add <code>max_requests</code></td></tr>\n<tr><td>Random 502/504 errors under load</td><td><code>timeout</code> too low for slow endpoints</td><td>Raise <code>timeout</code>, or fix the slow view/query</td></tr>\n<tr><td>Deploys cause brief downtime</td><td>Hard restart instead of graceful reload</td><td>Use the <code>HUP</code> signal -- see 1.7</td></tr>\n</table>\n</section>\n<section id=\"g7\">\n<h3><span>1.7</span>Signals and graceful reload</h3>\n<div class=\"callout\"><strong>Why this matters</strong>You want to deploy new code without dropping a single in-flight request. Gunicorn's signal handling makes that possible without any extra tooling.</div>\n<div class=\"tbl-wrap\">\n<table class=\"gtbl\">\n<tr><th>Signal</th><th>Effect</th></tr>\n<tr><td><code>TERM</code></td><td>Graceful shutdown -- finish in-flight requests, then exit</td></tr>\n<tr><td><code>HUP</code></td><td>Reload config and gracefully restart all workers, one at a time</td></tr>\n<tr><td><code>USR2</code> + <code>WINCH</code></td><td>Zero-downtime binary upgrade (start new master, hand off socket)</td></tr>\n<tr><td><code>TTIN</code> / <code>TTOU</code></td><td>Increase / decrease worker count live, without a restart</td></tr>\n</table>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-lang\">Terminal</span></div>\n<pre><span># After deploying new code, reload workers one-by-one with zero downtime</span>\nkill -HUP $(cat /run/gunicorn.pid)</pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> In practice you'll rarely send these signals by hand -- a process supervisor like <strong>systemd</strong> or your container orchestrator sends <code>TERM</code> automatically on restart, and Gunicorn's graceful shutdown handles the rest.</div>\n</section>\n<section id=\"n1\">\n<h3><span>2.1</span>What is Nginx?</h3>\n<div class=\"callout\"><strong>In one sentence</strong>Nginx is a high-performance web server that sits in front of Gunicorn, handling everything Gunicorn shouldn't have to: TLS, static files, slow clients, and traffic from the open internet.</div>\n<p><strong>Nginx</strong> (pronounced \"engine-x\") is a web server originally built to solve the \"C10K problem\" -- handling ten thousand concurrent connections on a single machine, something older servers struggled with badly. It does this using an event-driven, asynchronous architecture rather than spawning a process or thread per connection.</p>\n<p>In a Django stack, Nginx almost never talks to your database or runs any Python at all. Its job is narrower and more mechanical: accept every incoming HTTP/HTTPS connection, decide what kind of request it is, and either serve it directly (a static CSS file) or forward it to Gunicorn (a dynamic page that needs Django).</p>\n</section>\n<section id=\"n2\">\n<h3><span>2.2</span>The reverse proxy model</h3>\n<div class=\"callout\"><strong>Why this matters</strong>\"Reverse proxy\" is the term for everything Nginx does in this stack -- understanding the word demystifies the entire role.</div>\n<p>A normal (forward) proxy sits in front of <em>clients</em> and fetches resources on their behalf. A <strong>reverse proxy</strong> is the mirror image: it sits in front of <em>servers</em>, and from the outside world's point of view, it looks like the entire application. The actual application servers (Gunicorn, in this case) are hidden behind it, often with no public IP at all.</p>\n<div class=\"tbl-wrap\">\n<table class=\"gtbl\">\n<tr><th>Responsibility</th><th>Who handles it</th><th>Why</th></tr>\n<tr><td>TLS / HTTPS termination</td><td>Nginx</td><td>Cheap, well-tested C code; keeps certificate logic out of your app</td></tr>\n<tr><td>Static files (CSS, JS, images)</td><td>Nginx</td><td>Reads straight from disk -- no Python interpreter needed at all</td></tr>\n<tr><td>Slow / malicious clients</td><td>Nginx</td><td>Buffers slow uploads so a Gunicorn worker isn't tied up waiting</td></tr>\n<tr><td>Business logic, database queries</td><td>Gunicorn \u2192 Django</td><td>This is the part only your application code can do</td></tr>\n</table>\n</div>\n</section>\n<section id=\"n3\">\n<h3><span>2.3</span>The full request flow</h3>\n<p>Here is exactly what happens between a user clicking a link and a page rendering in their browser:</p>\n<div class=\"diagram\">\n<svg viewbox=\"0 0 800 340\" xmlns=\"http://www.w3.org/2000/svg\">\n<defs>\n<marker id=\"arrowTeal\" markerheight=\"8\" markerwidth=\"8\" orient=\"auto\" refx=\"6\" refy=\"4\"><path d=\"M0,0 L8,4 L0,8 Z\" fill=\"#2dd4bf\"></path></marker>\n<marker id=\"arrowAmber2\" markerheight=\"8\" markerwidth=\"8\" orient=\"auto\" refx=\"6\" refy=\"4\"><path d=\"M0,0 L8,4 L0,8 Z\" fill=\"#ffb020\"></path></marker>\n</defs>\n<!-- browser -->\n<rect fill=\"#171a22\" height=\"60\" rx=\"8\" stroke=\"#3a3f4e\" stroke-width=\"1.5\" width=\"120\" x=\"20\" y=\"140\"></rect>\n<text fill=\"#e9ebf1\" font-family=\"IBM Plex Mono, monospace\" font-size=\"12\" font-weight=\"600\" text-anchor=\"middle\" x=\"80\" y=\"165\">Browser</text>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"9.5\" text-anchor=\"middle\" x=\"80\" y=\"182\">GET /dashboard/</text>\n<line marker-end=\"url(#arrowTeal)\" stroke=\"#2dd4bf\" stroke-width=\"1.5\" x1=\"140\" x2=\"230\" y1=\"170\" y2=\"170\"></line>\n<text fill=\"#2dd4bf\" font-family=\"IBM Plex Mono, monospace\" font-size=\"9.5\" text-anchor=\"middle\" x=\"185\" y=\"160\">:443 HTTPS</text>\n<!-- nginx -->\n<rect fill=\"#0a0c10\" height=\"100\" rx=\"8\" stroke=\"#2dd4bf\" stroke-width=\"1.5\" width=\"150\" x=\"230\" y=\"120\"></rect>\n<text fill=\"#e9ebf1\" font-family=\"IBM Plex Mono, monospace\" font-size=\"13\" font-weight=\"600\" text-anchor=\"middle\" x=\"305\" y=\"148\">Nginx</text>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"9.5\" text-anchor=\"middle\" x=\"305\" y=\"165\">terminates TLS</text>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"9.5\" text-anchor=\"middle\" x=\"305\" y=\"180\">checks: static or</text>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"9.5\" text-anchor=\"middle\" x=\"305\" y=\"195\">dynamic request?</text>\n<!-- static branch -->\n<line marker-end=\"url(#arrowTeal)\" stroke=\"#80849a\" stroke-dasharray=\"3,3\" stroke-width=\"1.5\" x1=\"305\" x2=\"305\" y1=\"120\" y2=\"60\"></line>\n<rect fill=\"#171a22\" height=\"40\" rx=\"8\" stroke=\"#3a3f4e\" stroke-width=\"1.5\" width=\"150\" x=\"230\" y=\"20\"></rect>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"10.5\" text-anchor=\"middle\" x=\"305\" y=\"44\">/static/ on disk</text>\n<!-- dynamic branch to gunicorn -->\n<line marker-end=\"url(#arrowAmber2)\" stroke=\"#ffb020\" stroke-width=\"1.5\" x1=\"380\" x2=\"470\" y1=\"170\" y2=\"170\"></line>\n<text fill=\"#ffb020\" font-family=\"IBM Plex Mono, monospace\" font-size=\"9.5\" text-anchor=\"middle\" x=\"425\" y=\"160\">unix socket</text>\n<rect fill=\"#0a0c10\" height=\"100\" rx=\"8\" stroke=\"#ffb020\" stroke-width=\"1.5\" width=\"150\" x=\"470\" y=\"120\"></rect>\n<text fill=\"#e9ebf1\" font-family=\"IBM Plex Mono, monospace\" font-size=\"13\" font-weight=\"600\" text-anchor=\"middle\" x=\"545\" y=\"148\">Gunicorn</text>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"9.5\" text-anchor=\"middle\" x=\"545\" y=\"165\">picks a free</text>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"9.5\" text-anchor=\"middle\" x=\"545\" y=\"180\">worker process</text>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"9.5\" text-anchor=\"middle\" x=\"545\" y=\"195\">(see Chapter 1)</text>\n<line marker-end=\"url(#arrowTeal)\" stroke=\"#a78bfa\" stroke-width=\"1.5\" x1=\"620\" x2=\"690\" y1=\"170\" y2=\"170\"></line>\n<text fill=\"#a78bfa\" font-family=\"IBM Plex Mono, monospace\" font-size=\"9.5\" text-anchor=\"middle\" x=\"655\" y=\"160\">WSGI call</text>\n<rect fill=\"none\" height=\"100\" rx=\"8\" width=\"0\" x=\"690\" y=\"120\"></rect>\n<rect fill=\"#171a22\" height=\"80\" rx=\"8\" stroke=\"#a78bfa\" stroke-width=\"1.5\" width=\"150\" x=\"640\" y=\"240\"></rect>\n<text fill=\"#e9ebf1\" font-family=\"IBM Plex Mono, monospace\" font-size=\"12\" font-weight=\"600\" text-anchor=\"middle\" x=\"715\" y=\"265\">Django</text>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"9.5\" text-anchor=\"middle\" x=\"715\" y=\"282\">views, ORM,</text>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"9.5\" text-anchor=\"middle\" x=\"715\" y=\"297\">your code runs here</text>\n<line marker-end=\"url(#arrowTeal)\" stroke=\"#a78bfa\" stroke-width=\"1.5\" x1=\"545\" x2=\"700\" y1=\"220\" y2=\"240\"></line>\n<!-- return path -->\n<line stroke=\"#3a3f4e\" stroke-dasharray=\"2,3\" stroke-width=\"1.2\" x1=\"80\" x2=\"80\" y1=\"200\" y2=\"240\"></line>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"9\" text-anchor=\"middle\" x=\"80\" y=\"230\">\u2190 response returns the same path, reversed</text>\n</svg>\n</div>\n<p class=\"diagram-caption\">Static assets never leave Nginx. Only dynamic requests cross the socket into Gunicorn, and only Gunicorn ever calls into your Django code.</p>\n</section>\n<section id=\"n4\">\n<h3><span>2.4</span>A real server block configuration</h3>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-lang\">Nginx</span><span class=\"code-file\">/etc/nginx/sites-available/myproject</span></div>\n<pre><span>upstream</span> django_app {\n server unix:/run/gunicorn.sock;\n}\n\n<span>server</span> {\n listen <span>80</span>;\n server_name example.com www.example.com;\n\n <span>location</span> /static/ {\n alias /var/www/myproject/staticfiles/;\n expires <span>30d</span>;\n }\n\n <span>location</span> /media/ {\n alias /var/www/myproject/media/;\n }\n\n <span>location</span> / {\n proxy_pass http://django_app;\n proxy_set_header Host $host;\n proxy_set_header X-Real-IP $remote_addr;\n proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\n proxy_set_header X-Forwarded-Proto $scheme;\n }\n}</pre>\n</div>\n<p>The <code>upstream</code> block names the pool of backend servers Nginx can forward to -- here, just one Gunicorn socket, but it can list several Gunicorn instances for load balancing. Each <code>location</code> block matches a URL prefix and decides how to handle it: serve from disk, or proxy onward.</p>\n<div class=\"tone-danger\"><strong>Note:</strong> The three <code>proxy_set_header</code> lines matter more than they look. Without them, Django sees every request as coming from Nginx's local IP instead of the real visitor, which breaks logging, rate limiting, and anything relying on <code>request.META['REMOTE_ADDR']</code>.</div>\n</section>\n<section id=\"n5\">\n<h3><span>2.5</span>Serving static and media files efficiently</h3>\n<div class=\"callout\"><strong>Why this matters</strong>Sending a CSS file through Python is roughly a hundred times slower than letting Nginx read it straight off disk -- this is the single biggest performance win in the whole stack, and it's nearly free.</div>\n<p>Django's <code>collectstatic</code> command gathers every app's static files into one folder (<code>STATIC_ROOT</code>). Point Nginx's <code>alias</code> directive at that exact folder, and Nginx serves those files with zero Python involvement -- no WSGI call, no Gunicorn worker tied up, just a direct disk read.</p>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-lang\">Python</span><span class=\"code-file\">settings.py</span></div>\n<pre>STATIC_URL = <span>\"/static/\"</span>\nSTATIC_ROOT = BASE_DIR / <span>\"staticfiles\"</span> <span># collectstatic writes here</span>\n\nMEDIA_URL = <span>\"/media/\"</span>\nMEDIA_ROOT = BASE_DIR / <span>\"media\"</span> <span># user uploads land here</span></pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> The <code>expires 30d;</code> line in the static block tells browsers to cache the file for 30 days. Combine this with Django's cache-busting (<code>{% static %}</code> with hashed filenames via <code>ManifestStaticFilesStorage</code>) so updates still reach users immediately despite the long cache lifetime.</div>\n</section>\n<section id=\"n6\">\n<h3><span>2.6</span>TLS and HTTPS termination</h3>\n<p>\"TLS termination\" means Nginx is the place where encrypted HTTPS traffic gets decrypted back into plain HTTP before being forwarded to Gunicorn. Gunicorn and Django never need to know anything about certificates.</p>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-lang\">Nginx</span><span class=\"code-file\">HTTPS server block</span></div>\n<pre><span>server</span> {\n listen <span>443</span> ssl;\n server_name example.com;\n\n ssl_certificate /etc/letsencrypt/live/example.com/fullchain.pem;\n ssl_certificate_key /etc/letsencrypt/live/example.com/privkey.pem;\n ssl_protocols TLSv1.2 TLSv1.3;\n\n <span># ... same location blocks as before</span>\n}\n\n<span># Redirect all plain HTTP to HTTPS</span>\n<span>server</span> {\n listen <span>80</span>;\n server_name example.com;\n <span>return</span> <span>301</span> https://$host$request_uri;\n}</pre>\n</div>\n<div><strong>Let's Encrypt</strong> via <code>certbot</code> is the standard free way to get and auto-renew these certificate files -- <code>certbot --nginx</code> will even edit this config for you and set up the redirect automatically.</div>\n</section>\n<section id=\"n7\">\n<h3><span>2.7</span>Caching and rate limiting</h3>\n<p>Nginx can also absorb traffic before it ever reaches Django -- two directives cover most needs:</p>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-lang\">Nginx</span><span class=\"code-file\">rate limiting a login endpoint</span></div>\n<pre><span>limit_req_zone</span> $binary_remote_addr zone=login:10m rate=5r/m;\n\n<span>server</span> {\n <span># ...</span>\n <span>location</span> /accounts/login/ {\n limit_req zone=login burst=3 nodelay;\n proxy_pass http://django_app;\n }\n}</pre>\n</div>\n<p>This caps login attempts at 5 per minute per IP address, with a small burst allowance -- a first line of defense against brute-force attacks that costs zero Django code or database queries to enforce.</p>\n<div class=\"tone-tip\"><strong>Tip:</strong> For full-page caching of anonymous, rarely-changing pages, look at <code>proxy_cache_path</code> and <code>proxy_cache</code> directives -- but for most Django sites, Redis-backed caching inside Django itself (Chapter 4) is the more flexible and commonly used approach.</div>\n</section>\n<section id=\"w1\">\n<h3><span>3.1</span>What is WSGI?</h3>\n<div class=\"callout\"><strong>In one sentence</strong>WSGI is a standard Python function signature -- every WSGI server and every WSGI framework agree to speak through one simple callable, so any of them can be swapped for any other.</div>\n<p><strong>WSGI</strong> (Web Server Gateway Interface, <a href=\"https://peps.python.org/pep-3333/\" target=\"_blank\">PEP 3333</a>) is not software -- it's a <strong>specification</strong>. It defines exactly one thing: what a Python callable representing a web application must look like, so that any WSGI-compliant server (Gunicorn, uWSGI, mod_wsgi) can run any WSGI-compliant framework (Django, Flask) without either one knowing the other exists.</p>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-lang\">Python</span><span class=\"code-file\">the entire WSGI contract, simplified</span></div>\n<pre><span>def</span> <span>application</span>(environ, start_response):\n <span># environ: a dict describing the incoming request</span>\n <span># start_response: a function you call to set status + headers</span>\n start_response(<span>\"200 OK\"</span>, [(<span>\"Content-Type\"</span>, <span>\"text/plain\"</span>)])\n <span>return</span> [<span>b\"Hello, world\"</span>]</pre>\n</div>\n<p>Django's generated <code>wsgi.py</code> builds exactly this kind of callable -- it's just hidden behind <code>get_wsgi_application()</code>. Gunicorn imports it and calls it once per request, synchronously, start to finish.</p>\n<div>The key word is <strong>synchronous</strong>. A WSGI application receives a request, runs to completion, and returns a response -- it cannot pause mid-request to wait on something else (like a WebSocket message) without blocking that entire worker.</div>\n</section>\n<section id=\"w2\">\n<h3><span>3.2</span>What is ASGI?</h3>\n<div class=\"callout\"><strong>In one sentence</strong>ASGI is WSGI's async successor -- the same idea of a standard contract, but built around Python's <code>async</code>/<code>await</code> so a single worker can juggle many long-lived connections at once.</div>\n<p><strong>ASGI</strong> (Asynchronous Server Gateway Interface) was created because WSGI's one-request-at-a-time model fundamentally cannot support WebSockets, Server-Sent Events, or long-polling -- anything where a connection needs to stay open and exchange messages over time rather than complete in one request/response round trip.</p>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-lang\">Python</span><span class=\"code-file\">the ASGI contract, simplified</span></div>\n<pre><span>async def</span> <span>application</span>(scope, receive, send):\n <span># scope: connection info (http, websocket, lifespan...)</span>\n <span># receive(): awaitable, gets the next incoming event</span>\n <span># send(): awaitable, sends an event back to the client</span>\n <span>await</span> send({\n <span>\"type\"</span>: <span>\"http.response.start\"</span>,\n <span>\"status\"</span>: <span>200</span>,\n <span>\"headers\"</span>: [[<span>b\"content-type\"</span>, <span>b\"text/plain\"</span>]],\n })\n <span>await</span> send({<span>\"type\"</span>: <span>\"http.response.body\"</span>, <span>\"body\"</span>: <span>b\"Hello, async world\"</span>})</pre>\n</div>\n<p>Because it's built on <code>async</code>/<code>await</code>, a single ASGI worker can hold open thousands of idle WebSocket connections at once -- while waiting on one, the event loop simply serves others. This is structurally impossible for a sync WSGI worker, which can only ever be doing exactly one thing.</p>\n</section>\n<section id=\"w3\">\n<h3><span>3.3</span>Side-by-side comparison</h3>\n<div class=\"diagram\">\n<svg viewbox=\"0 0 760 260\" xmlns=\"http://www.w3.org/2000/svg\">\n<defs><marker id=\"arrowV\" markerheight=\"8\" markerwidth=\"8\" orient=\"auto\" refx=\"6\" refy=\"4\"><path d=\"M0,0 L8,4 L0,8 Z\" fill=\"#a78bfa\"></path></marker></defs>\n<!-- WSGI side -->\n<text fill=\"#ffb020\" font-family=\"Space Grotesk, sans-serif\" font-size=\"14\" font-weight=\"700\" text-anchor=\"middle\" x=\"190\" y=\"24\">WSGI \u00b7 Synchronous</text>\n<rect fill=\"#0a0c10\" height=\"46\" rx=\"6\" stroke=\"#3a3f4e\" stroke-width=\"1.3\" width=\"100\" x=\"60\" y=\"44\"></rect>\n<text fill=\"#e9ebf1\" font-family=\"IBM Plex Mono, monospace\" font-size=\"11\" text-anchor=\"middle\" x=\"110\" y=\"71\">Worker 1</text>\n<rect fill=\"#171a22\" height=\"36\" rx=\"6\" stroke=\"#ffb020\" stroke-width=\"1.3\" width=\"100\" x=\"60\" y=\"100\"></rect>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"9.5\" text-anchor=\"middle\" x=\"110\" y=\"122\">Request A only</text>\n<rect fill=\"#0a0c10\" height=\"46\" rx=\"6\" stroke=\"#3a3f4e\" stroke-width=\"1.3\" width=\"100\" x=\"220\" y=\"44\"></rect>\n<text fill=\"#e9ebf1\" font-family=\"IBM Plex Mono, monospace\" font-size=\"11\" text-anchor=\"middle\" x=\"270\" y=\"71\">Worker 2</text>\n<rect fill=\"#171a22\" height=\"36\" rx=\"6\" stroke=\"#ffb020\" stroke-width=\"1.3\" width=\"100\" x=\"220\" y=\"100\"></rect>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"9.5\" text-anchor=\"middle\" x=\"270\" y=\"122\">Request B only</text>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"10\" text-anchor=\"middle\" x=\"190\" y=\"160\">1 request = 1 worker, blocked</text>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"10\" text-anchor=\"middle\" x=\"190\" y=\"178\">until fully complete</text>\n<line stroke=\"none\" x1=\"380\" x2=\"380\" y1=\"120\" y2=\"120\"></line>\n<line stroke=\"#272b36\" stroke-width=\"1.5\" x1=\"378\" x2=\"378\" y1=\"20\" y2=\"220\"></line>\n<!-- ASGI side -->\n<text fill=\"#a78bfa\" font-family=\"Space Grotesk, sans-serif\" font-size=\"14\" font-weight=\"700\" text-anchor=\"middle\" x=\"590\" y=\"24\">ASGI \u00b7 Asynchronous</text>\n<rect fill=\"#0a0c10\" height=\"92\" rx=\"6\" stroke=\"#a78bfa\" stroke-width=\"1.3\" width=\"260\" x=\"460\" y=\"44\"></rect>\n<text fill=\"#e9ebf1\" font-family=\"IBM Plex Mono, monospace\" font-size=\"11\" font-weight=\"600\" text-anchor=\"middle\" x=\"590\" y=\"64\">One Worker, Event Loop</text>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"9.5\" text-anchor=\"middle\" x=\"590\" y=\"84\">Req A \u00b7 Req B \u00b7 WS conn C</text>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"9.5\" text-anchor=\"middle\" x=\"590\" y=\"100\">all progress concurrently,</text>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"9.5\" text-anchor=\"middle\" x=\"590\" y=\"116\">switching at each await</text>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"10\" text-anchor=\"middle\" x=\"590\" y=\"160\">Many connections share</text>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"10\" text-anchor=\"middle\" x=\"590\" y=\"178\">one process via cooperative multitasking</text>\n</svg>\n</div>\n<div>\n<div>\n<div>WSGI</div>\n<div><ul>\n<li>Synchronous, one request per worker at a time</li>\n<li>Simple mental model, easiest to debug</li>\n<li>No native WebSocket / long-polling support</li>\n<li>Scales by adding more processes (more RAM)</li>\n<li>Server: Gunicorn (sync workers)</li>\n</ul></div>\n</div>\n<div>\n<div>ASGI</div>\n<div><ul>\n<li>Asynchronous, many connections per worker</li>\n<li>Requires <code>async def</code> views to get full benefit</li>\n<li>Native WebSockets, SSE, long-polling support</li>\n<li>Scales by handling more I/O concurrency per process</li>\n<li>Server: Uvicorn, Daphne, or Hypercorn</li>\n</ul></div>\n</div>\n</div>\n</section>\n<section id=\"w4\">\n<h3><span>3.4</span>Running Django on ASGI</h3>\n<div class=\"callout\"><strong>Why this matters</strong>Since Django 3.0, every new project ships with an <code>asgi.py</code> file alongside <code>wsgi.py</code> -- switching servers doesn't require rewriting your views, only changing what entry point you run.</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-lang\">Python</span><span class=\"code-file\">myproject/asgi.py (Django's default)</span></div>\n<pre><span>import</span> os\n<span>from</span> django.core.asgi <span>import</span> get_asgi_application\n\nos.environ.setdefault(<span>\"DJANGO_SETTINGS_MODULE\"</span>, <span>\"myproject.settings\"</span>)\napplication = get_asgi_application()</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-lang\">Terminal</span></div>\n<pre>pip install uvicorn[standard]\nuvicorn myproject.asgi:application --host 0.0.0.0 --port 8000 --workers 4\n\n<span># or run Uvicorn's worker class *inside* Gunicorn -- gets you</span>\n<span># Gunicorn's process management with Uvicorn's async event loop</span>\ngunicorn myproject.asgi:application -k uvicorn.workers.UvicornWorker --workers 4</pre>\n</div>\n<p>Plain Django views still work completely unchanged under ASGI -- they just run synchronously inside the async server, which Django handles for you automatically via a thread-pool bridge. You only need to write <code>async def</code> views yourself when you want a specific view to actually benefit from non-blocking I/O.</p>\n<div>If your project also uses <strong>Django Channels</strong> for WebSockets, your <code>asgi.py</code> looks slightly different -- it wraps Django's ASGI app with a <code>ProtocolTypeRouter</code> that routes HTTP to Django and WebSocket connections to Channels consumers. Channels' real-time layer leans on Redis -- covered in 4.6.</div>\n</section>\n<section id=\"w5\">\n<h3><span>3.5</span>Choosing between them</h3>\n<p>This decision is almost always simpler than it first appears:</p>\n<ul>\n<li><strong>Stick with WSGI + Gunicorn</strong> if your site is standard request/response pages -- forms, dashboards, blogs, e-commerce, admin panels. This is most Django sites, and WSGI is simpler to run, debug, and reason about.</li>\n<li><strong>Move to ASGI</strong> only when you have a concrete need for it: live chat, real-time notifications, collaborative editing, live dashboards that push updates, or WebSocket-based features that WSGI structurally cannot support.</li>\n</ul>\n<div class=\"tone-tip\"><strong>Tip:</strong> You don't have to choose globally for your whole app. A common production pattern runs the bulk of the site on Gunicorn/WSGI, with a separate ASGI service (Daphne or Uvicorn) handling only the WebSocket routes, both sitting behind the same Nginx using path-based routing.</div>\n</section>\n<section id=\"r1\">\n<h3><span>4.1</span>What is Redis?</h3>\n<div class=\"callout\"><strong>In one sentence</strong>Redis is a database that lives entirely in RAM, which makes it extremely fast, and exactly the tool for the kind of short-lived, frequently-accessed data that doesn't belong in PostgreSQL.</div>\n<p>Recall from Chapter 1 that every Gunicorn worker is a <strong>separate, isolated process</strong> with its own memory. That isolation is great for reliability, but it creates a real problem: if Worker 2 caches a value in its own Python memory, Worker 1 has no way to see it. <strong>Redis solves this by living outside all of them</strong> -- a separate process every worker connects to over a fast local socket, so they all share one source of truth.</p>\n<div class=\"stat-grid\">\n<div class=\"stat-card\"><div>RAM</div><div>Primary storage location</div></div>\n<div class=\"stat-card\"><div>&lt;1ms</div><div>Typical local read latency</div></div>\n<div class=\"stat-card\"><div>Single-threaded</div><div>Core execution model</div></div>\n</div>\n<p>Because Redis is fundamentally a RAM-backed store, it's not meant to replace PostgreSQL as your system of record -- it's meant to sit alongside it for data that's fast-changing, short-lived, or read far more often than it's written.</p>\n</section>\n<section id=\"r2\">\n<h3><span>4.2</span>Data structures, not just key-value</h3>\n<div class=\"callout\"><strong>Why this matters</strong>Redis is often called a \"key-value store,\" which undersells it -- the value behind each key can be a rich structure with its own operations, not just a string.</div>\n<div class=\"tbl-wrap\">\n<table class=\"gtbl\">\n<tr><th>Structure</th><th>What it's for</th><th>Django/web use case</th></tr>\n<tr><td><code>STRING</code></td><td>Text, numbers, serialized objects</td><td>Cached page fragments, counters</td></tr>\n<tr><td><code>HASH</code></td><td>A flat object: field \u2192 value pairs</td><td>Session data, user profile cache</td></tr>\n<tr><td><code>LIST</code></td><td>An ordered, push/pop-able sequence</td><td>Simple task queues, recent-activity feeds</td></tr>\n<tr><td><code>SET</code></td><td>Unordered unique values</td><td>\"Online now\" user tracking, tag membership</td></tr>\n<tr><td><code>SORTED SET</code></td><td>Set with a score, kept ordered</td><td>Leaderboards, rate-limit windows</td></tr>\n<tr><td><code>PUB/SUB</code></td><td>Fire-and-forget broadcast channels</td><td>Django Channels layer (4.6)</td></tr>\n</table>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-lang\">Terminal</span><span class=\"code-file\">redis-cli session</span></div>\n<pre>redis-cli&gt; SET page:home:views 412\nOK\nredis-cli&gt; INCR page:home:views\n(integer) <span>413</span>\nredis-cli&gt; EXPIRE page:home:views <span>3600</span>\n(integer) <span>1</span>\nredis-cli&gt; ZADD leaderboard <span>980</span> <span>\"player_42\"</span>\n(integer) <span>1</span>\nredis-cli&gt; ZREVRANGE leaderboard <span>0</span> <span>2</span> WITHSCORES\n<span>1</span>) <span>\"player_42\"</span>\n<span>2</span>) <span>\"980\"</span></pre>\n</div>\n</section>\n<section id=\"r3\">\n<h3><span>4.3</span>Redis as Django's cache backend</h3>\n<div class=\"callout\"><strong>Why this matters</strong>This is the single most common reason Django projects add Redis at all -- caching expensive queries or rendered fragments so the database isn't hit on every request.</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-lang\">Terminal</span></div>\n<pre>pip install django-redis</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-lang\">Python</span><span class=\"code-file\">settings.py</span></div>\n<pre>CACHES = {\n <span>\"default\"</span>: {\n <span>\"BACKEND\"</span>: <span>\"django_redis.cache.RedisCache\"</span>,\n <span>\"LOCATION\"</span>: <span>\"redis://127.0.0.1:6379/1\"</span>,\n <span>\"OPTIONS\"</span>: {\n <span>\"CLIENT_CLASS\"</span>: <span>\"django_redis.client.DefaultClient\"</span>,\n },\n }\n}</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-lang\">Python</span><span class=\"code-file\">views.py -- caching an expensive query</span></div>\n<pre><span>from</span> django.core.cache <span>import</span> cache\n\n<span>def</span> <span>dashboard_view</span>(request):\n stats = cache.<span>get</span>(<span>\"dashboard_stats\"</span>)\n <span>if</span> stats <span>is</span> <span>None</span>:\n stats = <span>compute_expensive_stats</span>() <span># the slow database work</span>\n cache.<span>set</span>(<span>\"dashboard_stats\"</span>, stats, timeout=<span>300</span>) <span># 5 minutes</span>\n <span>return</span> render(request, <span>\"dashboard.html\"</span>, {<span>\"stats\"</span>: stats})</pre>\n</div>\n<p>The numeral after the host (<code>/1</code> in the URL above) is a Redis <strong>database index</strong> -- a lightweight namespace. It's common to use separate indexes for cache, sessions, and Celery so they don't collide if you ever need to flush one without touching the others.</p>\n</section>\n<section id=\"r4\">\n<h3><span>4.4</span>Storing sessions in Redis</h3>\n<div class=\"callout\"><strong>Why this matters</strong>Database-backed sessions add a query to nearly every logged-in request. Redis sessions remove that database round trip entirely and scale far better under load.</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-lang\">Python</span><span class=\"code-file\">settings.py</span></div>\n<pre>SESSION_ENGINE = <span>\"django.contrib.sessions.backends.cache\"</span>\nSESSION_CACHE_ALIAS = <span>\"default\"</span> <span># reuses the CACHES[\"default\"] config above</span></pre>\n</div>\n<div class=\"tone-danger\"><strong>Note:</strong> The plain <code>cache</code> session engine treats the cache as the only copy -- if Redis restarts and loses data (depending on persistence settings), every logged-in user is logged out. Use <code>cache_db</code> instead of <code>cache</code> if you want Redis speed with a PostgreSQL-backed fallback of record.</div>\n</section>\n<section id=\"r5\">\n<h3><span>4.5</span>Redis as a Celery broker and result backend</h3>\n<div class=\"callout\"><strong>Why this matters</strong>Anything that shouldn't block a Gunicorn worker -- sending an email, generating a PDF, calling a slow external API -- belongs in a background task. Celery needs a message broker to hand work to background workers, and Redis is the simplest one to operate.</div>\n<div class=\"diagram\">\n<svg viewbox=\"0 0 760 200\" xmlns=\"http://www.w3.org/2000/svg\">\n<defs><marker id=\"arrowR\" markerheight=\"8\" markerwidth=\"8\" orient=\"auto\" refx=\"6\" refy=\"4\"><path d=\"M0,0 L8,4 L0,8 Z\" fill=\"#ff4d4f\"></path></marker></defs>\n<rect fill=\"#171a22\" height=\"60\" rx=\"8\" stroke=\"#ffb020\" stroke-width=\"1.5\" width=\"150\" x=\"20\" y=\"70\"></rect>\n<text fill=\"#e9ebf1\" font-family=\"IBM Plex Mono, monospace\" font-size=\"12\" font-weight=\"600\" text-anchor=\"middle\" x=\"95\" y=\"95\">Django view</text>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"9.5\" text-anchor=\"middle\" x=\"95\" y=\"112\">task.delay(...)</text>\n<line marker-end=\"url(#arrowR)\" stroke=\"#ff4d4f\" stroke-width=\"1.5\" x1=\"170\" x2=\"290\" y1=\"100\" y2=\"100\"></line>\n<rect fill=\"#0a0c10\" height=\"60\" rx=\"8\" stroke=\"#ff4d4f\" stroke-width=\"1.5\" width=\"150\" x=\"290\" y=\"70\"></rect>\n<text fill=\"#e9ebf1\" font-family=\"IBM Plex Mono, monospace\" font-size=\"12\" font-weight=\"600\" text-anchor=\"middle\" x=\"365\" y=\"95\">Redis queue</text>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"9.5\" text-anchor=\"middle\" x=\"365\" y=\"112\">task waits here</text>\n<line marker-end=\"url(#arrowR)\" stroke=\"#ff4d4f\" stroke-width=\"1.5\" x1=\"440\" x2=\"560\" y1=\"100\" y2=\"100\"></line>\n<rect fill=\"#171a22\" height=\"60\" rx=\"8\" stroke=\"#3a3f4e\" stroke-width=\"1.5\" width=\"170\" x=\"560\" y=\"70\"></rect>\n<text fill=\"#e9ebf1\" font-family=\"IBM Plex Mono, monospace\" font-size=\"12\" font-weight=\"600\" text-anchor=\"middle\" x=\"645\" y=\"95\">Celery worker</text>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"9.5\" text-anchor=\"middle\" x=\"645\" y=\"112\">separate process, runs the task</text>\n<line stroke=\"#3a3f4e\" stroke-dasharray=\"2,3\" stroke-width=\"1.3\" x1=\"645\" x2=\"645\" y1=\"130\" y2=\"160\"></line>\n<line stroke=\"#3a3f4e\" stroke-dasharray=\"2,3\" stroke-width=\"1.3\" x1=\"365\" x2=\"365\" y1=\"130\" y2=\"160\"></line>\n<line marker-end=\"url(#arrowR)\" stroke=\"#3a3f4e\" stroke-dasharray=\"2,3\" stroke-width=\"1.3\" x1=\"645\" x2=\"365\" y1=\"160\" y2=\"160\"></line>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"9.5\" text-anchor=\"middle\" x=\"500\" y=\"178\">result stored back in Redis, view can poll for it</text>\n</svg>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-lang\">Terminal</span></div>\n<pre>pip install celery redis</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-lang\">Python</span><span class=\"code-file\">myproject/celery.py</span></div>\n<pre><span>import</span> os\n<span>from</span> celery <span>import</span> Celery\n\nos.environ.setdefault(<span>\"DJANGO_SETTINGS_MODULE\"</span>, <span>\"myproject.settings\"</span>)\napp = Celery(<span>\"myproject\"</span>)\napp.conf.broker_url = <span>\"redis://127.0.0.1:6379/2\"</span>\napp.conf.result_backend = <span>\"redis://127.0.0.1:6379/3\"</span>\napp.autodiscover_tasks()</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-lang\">Python</span><span class=\"code-file\">myapp/tasks.py</span></div>\n<pre><span>from</span> celery <span>import</span> shared_task\n\n<span>@shared_task</span>\n<span>def</span> <span>send_welcome_email</span>(user_id):\n user = User.objects.<span>get</span>(id=user_id)\n <span># slow SMTP call happens here, off the request/response path</span>\n send_mail(<span>\"Welcome!\"</span>, <span>\"...\"</span>, <span>\"from@example.com\"</span>, [user.email])</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-lang\">Terminal</span></div>\n<pre>celery -A myproject worker --loglevel=info</pre>\n</div>\n<p>Calling <code>send_welcome_email.delay(user.id)</code> from a view returns instantly -- Django pushes the task onto the Redis queue and moves on, while a separate Celery worker process picks it up and runs it whenever it's free.</p>\n</section>\n<section id=\"r6\">\n<h3><span>4.6</span>Redis as the Django Channels layer</h3>\n<div class=\"callout\"><strong>Why this matters</strong>Tying this back to Chapter 3: if you run Django on ASGI with Channels for WebSockets, Redis is what lets a message sent by one ASGI worker reach a WebSocket connection held open by a completely different worker.</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-lang\">Python</span><span class=\"code-file\">settings.py</span></div>\n<pre>CHANNEL_LAYERS = {\n <span>\"default\"</span>: {\n <span>\"BACKEND\"</span>: <span>\"channels_redis.core.RedisChannelLayer\"</span>,\n <span>\"CONFIG\"</span>: {\n <span>\"hosts\"</span>: [(<span>\"127.0.0.1\"</span>, <span>6379</span>)],\n },\n },\n}</pre>\n</div>\n<p>Without this, a chat message sent by a user connected to Worker A would have no way to reach a different user connected to Worker B -- each ASGI worker is just as isolated as a Gunicorn worker is. Redis's <code>PUB/SUB</code> structure is exactly the mechanism Channels uses to broadcast that message to every worker that needs it.</p>\n</section>\n<section id=\"d1\">\n<h3><span>5.1</span>What is Docker?</h3>\n<div class=\"callout\"><strong>In one sentence</strong>Docker packages an application together with everything it needs to run -- so \"works on my machine\" becomes \"works everywhere,\" because the machine is now part of the package.</div>\n<p>Before containers, deploying meant manually replicating an environment: install this exact Python version, these exact system packages, set these exact environment variables, hope nothing on the server conflicts with something else running on it. Every difference between your laptop and the server was a potential bug.</p>\n<p><strong>Docker</strong> solves this with <strong>containers</strong> -- lightweight, isolated environments that bundle your application with its own filesystem, libraries, and runtime, all defined in one text file. A container that runs correctly on your laptop will run identically on any other machine with Docker installed, because it isn't relying on anything from the host system except the Linux kernel itself.</p>\n<div>Containers are <strong>not</strong> virtual machines. A VM virtualizes an entire hardware stack and runs a full separate OS kernel -- heavy, slow to start. A container shares the host machine's kernel and only isolates the process, filesystem, and network -- lightweight, starts in milliseconds, and is what makes running a dozen containers on one server practical.</div>\n</section>\n<section id=\"d2\">\n<h3><span>5.2</span>Images, layers, and containers</h3>\n<div class=\"callout\"><strong>Why this matters</strong>These three words are used constantly and mean specific, different things -- mixing them up is the most common source of confusion for anyone new to Docker.</div>\n<div class=\"tbl-wrap\">\n<table class=\"gtbl\">\n<tr><th>Term</th><th>What it is</th></tr>\n<tr><td><strong>Dockerfile</strong></td><td>A text file of instructions for <em>building</em> an image -- the recipe</td></tr>\n<tr><td><strong>Image</strong></td><td>A built, immutable snapshot of a filesystem + metadata -- the baked cake</td></tr>\n<tr><td><strong>Container</strong></td><td>A running (or stopped) <em>instance</em> of an image -- the cake, sliced and on a plate</td></tr>\n<tr><td><strong>Layer</strong></td><td>One cached step of an image's build -- each Dockerfile instruction adds one</td></tr>\n</table>\n</div>\n<div class=\"diagram\">\n<svg viewbox=\"0 0 700 280\" xmlns=\"http://www.w3.org/2000/svg\">\n<text fill=\"#e9ebf1\" font-family=\"Space Grotesk, sans-serif\" font-size=\"14\" font-weight=\"700\" text-anchor=\"middle\" x=\"350\" y=\"24\">Image layers stack bottom-up</text>\n<g>\n<rect fill=\"#0a0c10\" height=\"34\" stroke=\"#2496ed\" stroke-width=\"1.3\" width=\"260\" x=\"220\" y=\"44\"></rect>\n<text fill=\"#e9ebf1\" font-family=\"IBM Plex Mono, monospace\" font-size=\"11\" text-anchor=\"middle\" x=\"350\" y=\"66\">COPY . /app (your code -- changes often)</text>\n</g>\n<g>\n<rect fill=\"#13161c\" height=\"34\" stroke=\"#3a3f4e\" stroke-width=\"1.3\" width=\"260\" x=\"220\" y=\"78\"></rect>\n<text fill=\"#b9bdcb\" font-family=\"IBM Plex Mono, monospace\" font-size=\"11\" text-anchor=\"middle\" x=\"350\" y=\"100\">RUN pip install -r requirements.txt</text>\n</g>\n<g>\n<rect fill=\"#171a22\" height=\"34\" stroke=\"#3a3f4e\" stroke-width=\"1.3\" width=\"260\" x=\"220\" y=\"112\"></rect>\n<text fill=\"#b9bdcb\" font-family=\"IBM Plex Mono, monospace\" font-size=\"11\" text-anchor=\"middle\" x=\"350\" y=\"134\">COPY requirements.txt /app</text>\n</g>\n<g>\n<rect fill=\"#1b1e28\" height=\"34\" stroke=\"#3a3f4e\" stroke-width=\"1.3\" width=\"260\" x=\"220\" y=\"146\"></rect>\n<text fill=\"#b9bdcb\" font-family=\"IBM Plex Mono, monospace\" font-size=\"11\" text-anchor=\"middle\" x=\"350\" y=\"168\">RUN apt-get install libpq-dev</text>\n</g>\n<g>\n<rect fill=\"#20232f\" height=\"34\" stroke=\"#3a3f4e\" stroke-width=\"1.3\" width=\"260\" x=\"220\" y=\"180\"></rect>\n<text fill=\"#b9bdcb\" font-family=\"IBM Plex Mono, monospace\" font-size=\"11\" text-anchor=\"middle\" x=\"350\" y=\"202\">FROM python:3.12-slim (base image)</text>\n</g>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"10.5\" text-anchor=\"middle\" x=\"350\" y=\"234\">Layers above an unchanged layer are rebuilt;</text>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"10.5\" text-anchor=\"middle\" x=\"350\" y=\"250\">layers below stay cached if their inputs didn't change</text>\n</svg>\n</div>\n<p class=\"diagram-caption\">Ordering matters: put what changes least often (system packages) near the bottom, and what changes most often (your code) near the top, so Docker's build cache stays useful.</p>\n</section>\n<section id=\"d3\">\n<h3><span>5.3</span>A real Dockerfile for Django</h3>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-lang\">Dockerfile</span><span class=\"code-file\">Dockerfile</span></div>\n<pre><span>FROM</span> python:3.12-slim\n\n<span># System dependencies (psycopg2 needs these to compile/run)</span>\n<span>RUN</span> apt-get update &amp;&amp; apt-get install -y \\\n libpq-dev gcc \\\n &amp;&amp; rm -rf /var/lib/apt/lists/*\n\n<span>ENV</span> PYTHONDONTWRITEBYTECODE=1 \\\n PYTHONUNBUFFERED=1\n\n<span>WORKDIR</span> /app\n\n<span># Copy requirements FIRST, before the rest of the code --</span>\n<span># this layer only rebuilds when dependencies actually change</span>\n<span>COPY</span> requirements.txt .\n<span>RUN</span> pip install --no-cache-dir -r requirements.txt\n\n<span># Now copy the actual application code</span>\n<span>COPY</span> . .\n\n<span>RUN</span> python manage.py collectstatic --noinput\n\n<span>EXPOSE</span> 8000\n<span>CMD</span> [<span>\"gunicorn\"</span>, <span>\"myproject.wsgi:application\"</span>, <span>\"--bind\"</span>, <span>\"0.0.0.0:8000\"</span>, <span>\"--workers\"</span>, <span>\"4\"</span>]</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-lang\">Terminal</span></div>\n<pre>docker build -t myproject:latest .\ndocker run -p 8000:8000 --env-file .env myproject:latest</pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> Always add a <code>.dockerignore</code> file (same syntax as <code>.gitignore</code>) excluding <code>venv/</code>, <code>__pycache__/</code>, <code>.git/</code>, and <code>media/</code> -- without it, Docker copies all of that into the image, bloating it and slowing every build.</div>\n</section>\n<section id=\"d4\">\n<h3><span>5.4</span>Multi-stage builds</h3>\n<div class=\"callout\"><strong>Why this matters</strong>Compilers, build tools, and dev dependencies bloat the final image and increase its attack surface -- a multi-stage build lets you use them during the build, then discard them from what actually ships.</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-lang\">Dockerfile</span><span class=\"code-file\">Dockerfile (multi-stage)</span></div>\n<pre><span># --- Stage 1: build ---</span>\n<span>FROM</span> python:3.12-slim AS builder\n<span>WORKDIR</span> /app\n<span>RUN</span> apt-get update &amp;&amp; apt-get install -y gcc libpq-dev\n<span>COPY</span> requirements.txt .\n<span>RUN</span> pip install --no-cache-dir --user -r requirements.txt\n\n<span># --- Stage 2: final, lean image ---</span>\n<span>FROM</span> python:3.12-slim\n<span>WORKDIR</span> /app\n<span>RUN</span> apt-get update &amp;&amp; apt-get install -y libpq5 &amp;&amp; rm -rf /var/lib/apt/lists/*\n<span>COPY</span> --from=builder /root/.local /root/.local\n<span>COPY</span> . .\n<span>ENV</span> PATH=/root/.local/bin:$PATH\n\n<span>EXPOSE</span> 8000\n<span>CMD</span> [<span>\"gunicorn\"</span>, <span>\"myproject.wsgi:application\"</span>, <span>\"--bind\"</span>, <span>\"0.0.0.0:8000\"</span>]</pre>\n</div>\n<p>The first stage has <code>gcc</code> and full build tooling needed to compile <code>psycopg2</code>. The second stage only needs the lighter <code>libpq5</code> runtime library and the already-compiled Python packages copied over -- <code>gcc</code> itself never makes it into the final image.</p>\n</section>\n<section id=\"d5\">\n<h3><span>5.5</span>docker-compose basics</h3>\n<div class=\"callout\"><strong>Why this matters</strong>A real Django app rarely runs alone -- it needs a database and usually Redis too. Compose defines all of them together in one file and brings the whole stack up with one command.</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-lang\">YAML</span><span class=\"code-file\">docker-compose.yml (minimal)</span></div>\n<pre><span>services</span>:\n <span>web</span>:\n <span>build</span>: .\n <span>ports</span>:\n - <span>\"8000:8000\"</span>\n <span>depends_on</span>:\n - db\n - redis\n\n <span>db</span>:\n <span>image</span>: postgres:16\n <span>environment</span>:\n POSTGRES_DB: myproject\n POSTGRES_PASSWORD: changeme\n\n <span>redis</span>:\n <span>image</span>: redis:7-alpine</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-lang\">Terminal</span></div>\n<pre>docker compose up -d <span># build + start everything, in the background</span>\ndocker compose logs -f web <span># follow logs from just the web service</span>\ndocker compose down <span># stop and remove containers</span></pre>\n</div>\n<p>Each top-level key under <code>services</code> becomes its own container, and Compose automatically creates a private network where every service can reach the others <strong>by name</strong> -- your Django settings connect to <code>db</code> and <code>redis</code> as hostnames, not IP addresses.</p>\n</section>\n<section id=\"d6\">\n<h3><span>5.6</span>Volumes and networks</h3>\n<div class=\"callout\"><strong>Why this matters</strong>Containers are disposable by design -- restart one and its filesystem resets. Volumes are how you keep database data and user uploads alive across restarts anyway.</div>\n<div class=\"tbl-wrap\">\n<table class=\"gtbl\">\n<tr><th>Concept</th><th>What it solves</th></tr>\n<tr><td><strong>Named volume</strong></td><td>Persistent storage Docker manages for you, survives container removal</td></tr>\n<tr><td><strong>Bind mount</strong></td><td>Maps a host folder directly into the container -- great for live dev code reload</td></tr>\n<tr><td><strong>Network</strong></td><td>A private virtual network so containers reach each other by service name</td></tr>\n</table>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-lang\">YAML</span><span class=\"code-file\">docker-compose.yml (with persistence)</span></div>\n<pre><span>services</span>:\n <span>db</span>:\n <span>image</span>: postgres:16\n <span>volumes</span>:\n - postgres_data:/var/lib/postgresql/data <span># named volume, persists</span>\n\n<span>volumes</span>:\n <span>postgres_data</span>:</pre>\n</div>\n<div class=\"tone-danger\"><strong>Note:</strong> Without that volume mapping, running <code>docker compose down -v</code> or simply removing the database container would <strong>permanently delete every row in your database</strong>. Always confirm your data-bearing services have volumes before going anywhere near production.</div>\n</section>\n<section id=\"c1\">\n<h3><span>6.1</span>The full architecture</h3>\n<div class=\"diagram\">\n<svg viewbox=\"0 0 820 420\" xmlns=\"http://www.w3.org/2000/svg\">\n<defs><marker id=\"arrowG\" markerheight=\"8\" markerwidth=\"8\" orient=\"auto\" refx=\"6\" refy=\"4\"><path d=\"M0,0 L8,4 L0,8 Z\" fill=\"#3fb950\"></path></marker></defs>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"10.5\" letter-spacing=\"1\" text-anchor=\"middle\" x=\"410\" y=\"22\">INTERNET</text>\n<rect fill=\"#171a22\" height=\"38\" rx=\"6\" stroke=\"#3a3f4e\" stroke-width=\"1.3\" width=\"120\" x=\"350\" y=\"32\"></rect>\n<text fill=\"#e9ebf1\" font-family=\"IBM Plex Mono, monospace\" font-size=\"11\" text-anchor=\"middle\" x=\"410\" y=\"55\">User Browser</text>\n<line marker-end=\"url(#arrowG)\" stroke=\"#2dd4bf\" stroke-width=\"1.5\" x1=\"410\" x2=\"410\" y1=\"70\" y2=\"96\"></line>\n<!-- dashed host boundary -->\n<rect fill=\"none\" height=\"300\" rx=\"10\" stroke=\"#272b36\" stroke-dasharray=\"5,4\" stroke-width=\"1.3\" width=\"740\" x=\"40\" y=\"96\"></rect>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"10\" x=\"60\" y=\"116\">docker compose stack (one host)</text>\n<!-- nginx container -->\n<rect fill=\"#0a0c10\" height=\"56\" rx=\"8\" stroke=\"#2dd4bf\" stroke-width=\"1.5\" width=\"160\" x=\"330\" y=\"126\"></rect>\n<text fill=\"#e9ebf1\" font-family=\"IBM Plex Mono, monospace\" font-size=\"12\" font-weight=\"600\" text-anchor=\"middle\" x=\"410\" y=\"150\">nginx</text>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"9.5\" text-anchor=\"middle\" x=\"410\" y=\"166\">:80 / :443 -- TLS, static</text>\n<line marker-end=\"url(#arrowG)\" stroke=\"#ffb020\" stroke-width=\"1.5\" x1=\"410\" x2=\"410\" y1=\"182\" y2=\"210\"></line>\n<!-- web container (gunicorn+django) -->\n<rect fill=\"#171a22\" height=\"60\" rx=\"8\" stroke=\"#ffb020\" stroke-width=\"1.5\" width=\"240\" x=\"290\" y=\"210\"></rect>\n<text fill=\"#e9ebf1\" font-family=\"IBM Plex Mono, monospace\" font-size=\"12\" font-weight=\"600\" text-anchor=\"middle\" x=\"410\" y=\"232\">web</text>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"9.5\" text-anchor=\"middle\" x=\"410\" y=\"248\">gunicorn + django (wsgi)</text>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"9.5\" text-anchor=\"middle\" x=\"410\" y=\"262\">:8000 internal</text>\n<!-- db container -->\n<rect fill=\"#0a0c10\" height=\"60\" rx=\"8\" stroke=\"#3a3f4e\" stroke-width=\"1.5\" width=\"160\" x=\"70\" y=\"300\"></rect>\n<text fill=\"#e9ebf1\" font-family=\"IBM Plex Mono, monospace\" font-size=\"12\" font-weight=\"600\" text-anchor=\"middle\" x=\"150\" y=\"324\">db</text>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"9.5\" text-anchor=\"middle\" x=\"150\" y=\"340\">postgres:16 + volume</text>\n<!-- redis container -->\n<rect fill=\"#0a0c10\" height=\"60\" rx=\"8\" stroke=\"#ff4d4f\" stroke-width=\"1.5\" width=\"160\" x=\"330\" y=\"300\"></rect>\n<text fill=\"#e9ebf1\" font-family=\"IBM Plex Mono, monospace\" font-size=\"12\" font-weight=\"600\" text-anchor=\"middle\" x=\"410\" y=\"324\">redis</text>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"9.5\" text-anchor=\"middle\" x=\"410\" y=\"340\">cache + celery broker</text>\n<!-- celery worker container -->\n<rect fill=\"#0a0c10\" height=\"60\" rx=\"8\" stroke=\"#3a3f4e\" stroke-width=\"1.5\" width=\"170\" x=\"590\" y=\"300\"></rect>\n<text fill=\"#e9ebf1\" font-family=\"IBM Plex Mono, monospace\" font-size=\"12\" font-weight=\"600\" text-anchor=\"middle\" x=\"675\" y=\"324\">celery_worker</text>\n<text fill=\"#80849a\" font-family=\"IBM Plex Mono, monospace\" font-size=\"9.5\" text-anchor=\"middle\" x=\"675\" y=\"340\">background tasks</text>\n<line marker-end=\"url(#arrowG)\" stroke=\"#3a3f4e\" stroke-width=\"1.4\" x1=\"350\" x2=\"180\" y1=\"270\" y2=\"300\"></line>\n<line marker-end=\"url(#arrowG)\" stroke=\"#ff4d4f\" stroke-width=\"1.4\" x1=\"410\" x2=\"410\" y1=\"270\" y2=\"300\"></line>\n<line marker-end=\"url(#arrowG)\" stroke=\"#3a3f4e\" stroke-width=\"1.4\" x1=\"470\" x2=\"650\" y1=\"270\" y2=\"300\"></line>\n<line marker-end=\"url(#arrowG)\" stroke=\"#ff4d4f\" stroke-dasharray=\"3,3\" stroke-width=\"1.3\" x1=\"600\" x2=\"460\" y1=\"300\" y2=\"320\"></line>\n</svg>\n</div>\n<p class=\"diagram-caption\">Every box is its own container; the dashed border is the single host they all run on, brought up together by one <code>docker compose up</code>.</p>\n</section>\n<section id=\"c2\">\n<h3><span>6.2</span>The complete docker-compose.yml</h3>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-lang\">YAML</span><span class=\"code-file\">docker-compose.yml</span></div>\n<pre><span>services</span>:\n <span>nginx</span>:\n <span>image</span>: nginx:1.27-alpine\n <span>ports</span>:\n - <span>\"80:80\"</span>\n - <span>\"443:443\"</span>\n <span>volumes</span>:\n - ./nginx.conf:/etc/nginx/conf.d/default.conf:ro\n - static_data:/app/staticfiles:ro\n - media_data:/app/media:ro\n <span>depends_on</span>:\n - web\n\n <span>web</span>:\n <span>build</span>: .\n <span>command</span>: gunicorn myproject.wsgi:application --bind 0.0.0.0:8000 --workers 4\n <span>volumes</span>:\n - static_data:/app/staticfiles\n - media_data:/app/media\n <span>env_file</span>: .env\n <span>depends_on</span>:\n - db\n - redis\n\n <span>celery_worker</span>:\n <span>build</span>: .\n <span>command</span>: celery -A myproject worker --loglevel=info\n <span>env_file</span>: .env\n <span>depends_on</span>:\n - redis\n - db\n\n <span>db</span>:\n <span>image</span>: postgres:16\n <span>environment</span>:\n POSTGRES_DB: ${POSTGRES_DB}\n POSTGRES_USER: ${POSTGRES_USER}\n POSTGRES_PASSWORD: ${POSTGRES_PASSWORD}\n <span>volumes</span>:\n - postgres_data:/var/lib/postgresql/data\n\n <span>redis</span>:\n <span>image</span>: redis:7-alpine\n <span>volumes</span>:\n - redis_data:/data\n\n<span>volumes</span>:\n <span>postgres_data</span>:\n <span>redis_data</span>:\n <span>static_data</span>:\n <span>media_data</span>:</pre>\n</div>\n<p>Notice that <strong>web</strong> and <strong>celery_worker</strong> both build from the same <code>Dockerfile</code> -- they're the same application code, just started with a different <code>command</code>. This is the standard pattern: one image, multiple roles, defined entirely by what each service tells it to run.</p>\n</section>\n<section id=\"c3\">\n<h3><span>6.3</span>Environment variables and secrets</h3>\n<div class=\"callout\"><strong>Why this matters</strong>Every credential above (database password, secret key) needs to exist somewhere -- and that place must never be your Dockerfile or your git history.</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-lang\">Text</span><span class=\"code-file\">.env (never committed -- add to .gitignore)</span></div>\n<pre>DJANGO_SETTINGS_MODULE=myproject.settings.production\nSECRET_KEY=<span>change-me-to-a-real-random-secret</span>\nALLOWED_HOSTS=example.com,www.example.com\n\nPOSTGRES_DB=myproject\nPOSTGRES_USER=myproject_user\nPOSTGRES_PASSWORD=<span>change-me-too</span>\nDATABASE_URL=postgres://myproject_user:change-me-too@db:5432/myproject\n\nREDIS_URL=redis://redis:6379/0\nCELERY_BROKER_URL=redis://redis:6379/2</pre>\n</div>\n<p>Notice the hostnames: <code>db</code> and <code>redis</code>, not <code>127.0.0.1</code>. Inside the Compose network, every service is reachable by its service name -- Django's <code>DATABASE_URL</code> connects to a container named <code>db</code> the same way your browser connects to a domain name.</p>\n<div class=\"tone-danger\"><strong>Note:</strong> Add <code>.env</code> to <code>.gitignore</code> immediately, before you ever fill in real values. Commit a <code>.env.example</code> with placeholder values instead, so teammates know what variables they need to set.</div>\n</section>\n<section id=\"c4\">\n<h3><span>6.4</span>Build, ship, and update workflow</h3>\n<div class=\"callout\"><strong>Why this matters</strong>This is the loop you'll run for the entire life of the project -- locally while developing, then on the server for every release.</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-lang\">Terminal</span><span class=\"code-file\">first launch</span></div>\n<pre>docker compose build\ndocker compose up -d\ndocker compose <span>exec</span> web python manage.py migrate\ndocker compose <span>exec</span> web python manage.py createsuperuser</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\"><span class=\"code-lang\">Terminal</span><span class=\"code-file\">every later update</span></div>\n<pre><span># On your machine: commit and push as normal</span>\ngit add . &amp;&amp; git commit -m <span>\"Add tournament recap feature\"</span> &amp;&amp; git push\n\n<span># On the server</span>\ngit pull origin main\ndocker compose build web celery_worker <span># rebuild only what changed</span>\ndocker compose <span>exec</span> web python manage.py migrate\ndocker compose up -d <span># recreates containers with new images</span>\ndocker compose logs -f web <span># confirm it came up healthy</span></pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> Run <code>docker compose exec web python manage.py migrate</code> <strong>before</strong> <code>docker compose up -d</code> swaps in the new code -- same rule as Gunicorn's bare-metal deploy in Chapter 1: schema changes go in before the new code that expects them goes live.</div>\n<div>For zero-downtime updates beyond a single host, the next step up is an orchestrator like Docker Swarm or Kubernetes, which can roll new containers in one at a time while old ones keep serving traffic -- worth reaching for once a single-host restart's few seconds of downtime actually matters to your users.</div>\n</section>\n<section id=\"cheatsheet\">\n<h2>Infrastructure Cheat Sheet</h2>\n<p class=\"section-sub\">Quick-reference commands and config snippets across Gunicorn, Nginx, WSGI/ASGI, Redis, and Docker.</p>\n<div class=\"cheat-grid\">\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Gunicorn</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>gunicorn app.wsgi:application</code><span>Run with default sync workers</span></div>\n<div class=\"cheat-item\"><code>--workers N</code><span>Set worker count, ~(2\u00d7cores)+1</span></div>\n<div class=\"cheat-item\"><code>--bind unix:/run/gunicorn.sock</code><span>Bind to a Unix socket for Nginx</span></div>\n<div class=\"cheat-item\"><code>kill -HUP $(cat gunicorn.pid)</code><span>Graceful reload, zero downtime</span></div>\n<div class=\"cheat-item\"><code>max_requests = 1000</code><span>Auto-restart workers to fight leaks</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Nginx</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>nginx -t</code><span>Test config syntax before reloading</span></div>\n<div class=\"cheat-item\"><code>systemctl reload nginx</code><span>Apply config without dropping connections</span></div>\n<div class=\"cheat-item\"><code>proxy_pass http://upstream</code><span>Forward request to Gunicorn</span></div>\n<div class=\"cheat-item\"><code>alias /path/;</code><span>Serve static files directly from disk</span></div>\n<div class=\"cheat-item\"><code>limit_req_zone</code><span>Rate-limit by client IP</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>WSGI / ASGI</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>wsgi.py</code><span>Sync entry point, default Django</span></div>\n<div class=\"cheat-item\"><code>asgi.py</code><span>Async entry point, since Django 3.0</span></div>\n<div class=\"cheat-item\"><code>uvicorn app.asgi:application</code><span>Run an ASGI app directly</span></div>\n<div class=\"cheat-item\"><code>-k uvicorn.workers.UvicornWorker</code><span>Run ASGI under Gunicorn's process model</span></div>\n<div class=\"cheat-item\"><code>async def view(request)</code><span>Native async Django view</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Redis</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>redis-cli ping</code><span>Confirm Redis is alive (returns PONG)</span></div>\n<div class=\"cheat-item\"><code>SET key value EX 300</code><span>Set a key with a 300s expiry</span></div>\n<div class=\"cheat-item\"><code>cache.get / cache.set</code><span>Django's cache API over Redis</span></div>\n<div class=\"cheat-item\"><code>celery -A app worker</code><span>Start a Celery worker against Redis</span></div>\n<div class=\"cheat-item\"><code>channels_redis</code><span>Channel layer for Django Channels</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Docker</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>docker build -t name .</code><span>Build an image from a Dockerfile</span></div>\n<div class=\"cheat-item\"><code>docker compose up -d</code><span>Start the whole stack, detached</span></div>\n<div class=\"cheat-item\"><code>docker compose exec web bash</code><span>Shell into a running container</span></div>\n<div class=\"cheat-item\"><code>docker compose logs -f web</code><span>Follow logs from one service</span></div>\n<div class=\"cheat-item\"><code>docker system prune</code><span>Clean up unused images/containers</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Pre-deploy Checklist</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>DEBUG=False</code><span>Never run with DEBUG on in production</span></div>\n<div class=\"cheat-item\"><code>.env in .gitignore</code><span>Secrets never enter git history</span></div>\n<div class=\"cheat-item\"><code>named volumes</code><span>Database and media data must persist</span></div>\n<div class=\"cheat-item\"><code>migrate before restart</code><span>Schema changes land before new code runs</span></div>\n<div class=\"cheat-item\"><code>check --deploy</code><span>Run Django's built-in security audit</span></div>\n</div>\n</div>\n</div>\n</section>";

